void fn_n(const MatrixView *a, int reorder, BsrPack *c) {
    int nb = a->nblocks;
    int bs = a->bs;
    int dim = a->n;
    int ptr = 0;

    memset(c, 0, sizeof(*c));
    c->n = dim;
    c->bs = bs;
    c->nblocks = nb;
    c->reorder = reorder;
    for (int i = 0; i < nb; i++) {
        c->perm[i] = a->perm[i];
    }

    // Pack in *packed block coordinates* (bi,bj). When reordered, packed block
    // index i maps to global block index perm[i]. We store col_idx as packed bj.
    for (int bi = 0; bi < nb; bi++) {
        int row_blk = reorder ? a->perm[bi] : bi; // global block for this packed row
        c->row_ptr[bi] = ptr;

        for (int bj = 0; bj < nb; bj++) {
            int col_blk = reorder ? a->perm[bj] : bj; // global block for this packed col
            int has = 0;

            for (int r = 0; r < bs; r++) {
                for (int cc = 0; cc < bs; cc++) {
                    int gr = row_blk * bs + r;
                    int gc = col_blk * bs + cc;
                    double v = a->a[gr * dim + gc];
                    if (fabs(v) > 0.0) {
                        has = 1;
                    }
