            }

            if (has) {
                c->col_idx[ptr] = bj; // packed column index
                for (int r = 0; r < bs; r++) {
                    for (int cc = 0; cc < bs; cc++) {
                        int gr = row_blk * bs + r;
                        int gc = col_blk * bs + cc;
                        c->data[ptr * bs * bs + r * bs + cc] = a->a[gr * dim + gc];
                    }
                }
                ptr++;
            }
        }
    }

    c->row_ptr[nb] = ptr;

    // Jacobi preconditioner diagonal inverse in *packed scalar coordinates*.
    for (int i = 0; i < dim; i++) {
        c->diag_inv[i] = 1.0;
    }
    for (int bi = 0; bi < nb; bi++) {
        int start = c->row_ptr[bi];
        int end = c->row_ptr[bi + 1];
        for (int k = start; k < end; k++) {
            if (c->col_idx[k] == bi) {
                for (int r = 0; r < bs; r++) {
                    double d = c->data[k * bs * bs + r * bs + r];
                    if (fabs(d) > 1e-14) {
