void bsr_matvec(const BsrPack *pack, const double *x, double *y) {
    int nb = pack->nblocks;
    int bs = pack->bs;
    int dim = pack->n;

    for (int i = 0; i < dim; i++) {
        y[i] = 0.0;
    }

    for (int bi = 0; bi < nb; bi++) {
        int start = pack->row_ptr[bi];
        int end = pack->row_ptr[bi + 1];
        int row_blk = pack->reorder ? pack->perm[bi] : bi; // global block

        for (int k = start; k < end; k++) {
            int bj = pack->col_idx[k];
            int col_blk = pack->reorder ? pack->perm[bj] : bj; // global block

            for (int r = 0; r < bs; r++) {
                for (int c = 0; c < bs; c++) {
                    int gi = row_blk * bs + r;
                    int gj = col_blk * bs + c;
                    y[gi] += pack->data[k * bs * bs + r * bs + c] * x[gj];
                }
            }
        }
    }
}
